import React from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../../types';

export type LiquibaseProps = IconProps;

const LiquibaseLight: React.FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title && <title>{title}</title>}
    <path
      d="M7.979 1c3.11 0 5.289 1.111 5.289 2.133s-2.178 2.134-5.29 2.134c-3.11 0-5.289-1.111-5.289-2.134S4.867 1 7.98 1M8.112 12.423c-1.689.4-3.422.844-4.533 1.555-.534-.355-.845-.755-.845-1.111 0-1.689 2.8-2.311 5.512-2.933 1.955-.445 3.955-.89 5.067-1.823v1.467c-.045 1.645-2.667 2.267-5.2 2.845M8.021 9.088c-2.044.445-4.178.934-5.334 1.956v-.356c0-2.933 3.2-3.689 6.312-4.4 2.267-.533 3.333-.8 4.267-1.556v1.645c0 1.511-2.667 2.133-5.245 2.711M13.268 11.443c-1.112.934-3.067 1.378-4.978 1.867-1.378.311-2.756.667-3.778 1.156.889.31 2.089.533 3.422.533 3.067 0 5.29-1.111 5.29-2.133v-1.423z"
      fill="#6C707E"
    />
  </svg>
);

const LiquibaseDark: React.FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title && <title>{title}</title>}
    <path
      d="M7.979 1c3.11 0 5.289 1.111 5.289 2.133s-2.178 2.134-5.29 2.134c-3.11 0-5.289-1.111-5.289-2.134S4.867 1 7.98 1M8.112 12.423c-1.689.4-3.422.844-4.533 1.555-.534-.355-.845-.755-.845-1.111 0-1.689 2.8-2.311 5.512-2.933 1.955-.445 3.955-.89 5.067-1.823v1.467c-.045 1.645-2.667 2.267-5.2 2.845M8.021 9.088c-2.044.445-4.178.934-5.334 1.956v-.356c0-2.933 3.2-3.689 6.312-4.4 2.267-.533 3.333-.8 4.267-1.556v1.645c0 1.511-2.667 2.133-5.245 2.711M13.268 11.443c-1.112.934-3.067 1.378-4.978 1.867-1.378.311-2.756.667-3.778 1.156.889.31 2.089.533 3.422.533 3.067 0 5.29-1.111 5.29-2.133v-1.423z"
      fill="#CED0D6"
    />
  </svg>
);

export const Liquibase: React.FC<LiquibaseProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? LiquibaseLight : LiquibaseDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
